using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9 renamed the discriminator property from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", so keep the old name.
            b.HasDiscriminator<string>("Discriminator");

            // EF9 removed the discriminator prefix from id values.
            // Existing documents have id format "Product|123", so keep it.
            b.HasDiscriminatorInJsonId();

            // EF9 maps the key property directly to the JSON "id" field.
            // Existing documents store Id separately; keep the shadow id.
            b.HasShadowId();
        });
    }
}
