class CosmosQuery
{
    // EF9: sync I/O (ToList, SaveChanges, etc.) now throws by default.
    // Must use async APIs (ToListAsync, SaveChangesAsync).
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL is safe: we preserved "Discriminator" via HasDiscriminator.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

